Deno.serve(async (req) => {
  const base44 = createClientFromRequest(req);
  let inserted = 0;
  const errors: string[] = [];
  const batchSize = 100;
  for (let i = 0; i < ALL_RECORDS.length; i += batchSize) {
    const batch = ALL_RECORDS.slice(i, i + batchSize);
    try {
      await base44.asServiceRole.entities.SessionLog.create(batch);
      inserted += batch.length;
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      errors.push(`batch ${i}: ${msg}`);
    }
  }
  return Response.json({ success: true, inserted, errors, total: ALL_RECORDS.length });
});
